func TestSchedulesDryRunSubstitutesDatePathParams(t *testing.T) {
	t.Setenv("FLIGHT_GOAT_CONFIG", t.TempDir()+"/missing.toml")
	t.Setenv("FLIGHT_GOAT_BASE_URL", "https://example.test/aeroapi")

	var flags rootFlags
	cmd := newRootCmd(&flags)
	cmd.SetArgs([]string{
		"--dry-run",
		"schedules",
		"--date-start", "2026-05-17",
		"--date-end", "2026-05-18",
		"--origin", "HAM",
		"--destination", "CDG",
	})
	cmd.SetOut(io.Discard)

	stderr := captureStderr(t, func() {
		if err := cmd.Execute(); err != nil {
			t.Fatalf("execute schedules dry-run: %v", err)
		}
	})

	if !strings.Contains(stderr, "GET https://example.test/aeroapi/schedules/2026-05-17/2026-05-18") {
		t.Fatalf("dry-run path did not include substituted date params:\n%s", stderr)
	}
	if strings.Contains(stderr, "{date_start}") || strings.Contains(stderr, "{date_end}") {
		t.Fatalf("dry-run path still contained template placeholders:\n%s", stderr)
	}
	if strings.Contains(stderr, "date_start=") || strings.Contains(stderr, "date_end=") {
		t.Fatalf("dry-run query still contained path params:\n%s", stderr)
	}
}

